import { Component, h, Prop, Event, EventEmitter, Host, Fragment } from '@stencil/core';
import { isNullOrUndefined, iconPrefixElement } from '@src/utils/mx-utils/utils';
import { IMxSingleSelectListItemAction } from './mx-single-select-list-item.model';
import { iSelectedItem, SelectListItem } from '@src/utils/mx-utils/calendar-service';

@Component({
  tag: 'mx-single-select-list-item',
  styleUrl: 'mx-single-select-list-item.css'
})
export class MxSingleSelectListItem {
  /** Sets the item. */
  @Prop() readonly item: SelectListItem;
  /** Sets the selected item. */
  @Prop({ mutable: true }) selectedItem: iSelectedItem;
  /** Sets the index of the <li> tab. */
  @Prop() readonly liTabindex: number;
  /** Sets the item to emit ONLY the value. */
  @Prop() readonly emitOnlyValue: boolean;
  /** Sets the index of the active selected item. */
  @Prop() readonly activeIndex: number;
  /** Sets the array of actions. */
  @Prop() readonly actions: Array<IMxSingleSelectListItemAction>;
  /** Sets is list item is highlight or not . */
  @Prop() readonly isHighlighted: boolean = false;
  /** Sets the index of tyhe item */
  @Prop() readonly index: number;
  /** Sets the index for highlighting the item using mouse . */
  @Prop() readonly setHighlightedIndex: (index: number) => void;
  /** Emits the item selected. */
  @Event() itemSelected: EventEmitter;
  /** Emits an event whenever the list is closed */
  @Event() close: EventEmitter;


  constructor() {
    this.item = { label: undefined, value: undefined };
    this.liTabindex = -1;
    this.emitOnlyValue = false;
    this.activeIndex = -1;
  }

  private readonly selectItem = (item) => (event) => {
    if (isNullOrUndefined(item)) {
      return;
    }
    if (item.children) {
      return;
    }
    if (item.disabled) {
      event.preventDefault();
      return;
    }
    this.selectedItem = item;
    this.itemSelected.emit(item);
  };

  private reverseCondition(condition) {
    return !condition;
  }

  private readonly handleActionInteractions = (action) => (event) => {
    if (action.stopPropagation && action.stopPropagation(this.item)) {
      event.stopPropagation();
    }
    if (!isNullOrUndefined(action.handler) && !this.item.disabled) {
      action.handler(this.item);
    }
    if (action.closeDropDown) {
      this.close.emit({ item: this.item, action: action });
    }
  };

  render() {
    const actionsFiltered =
      this.actions == null ? []
        : this.actions.filter((action: IMxSingleSelectListItemAction) => {
          return this.reverseCondition(action.condition) || action.condition(this.item);
        });

    return (
      <Host>
        <div title={this.item.label}>
          <li
            role='option'
            aria-selected={this.item.value === this.selectedItem?.value ? "true" : "false"}
            class={{
              'mx-list-item items overlay-nc ': true,
              // eslint-disable-next-line max-len
              'mx-active mx-selected bg-accent-less-prominent text-primary-inverse':
                this.item.value === this.selectedItem?.value && this.index === this.activeIndex,
              'mx-active bg-accent-less-prominent text-primary-inverse':
                this.item.value !== this.selectedItem?.value && this.index === this.activeIndex,
              'bg-primary text-primary hover:bg-quaternary-fill': this.index !== this.activeIndex,
              'mx-parent-item': this.item.isParent && !this.item.isLeafNode,
              'mx-disabled text-tertiary': this.item.disabled,
              highlighted: this.isHighlighted
            }}
            value={this.item.value}
            onClick={this.selectItem(this.item)}
            onMouseEnter={() => this.setHighlightedIndex?.(this.index)}
            tabindex={this.item.children ? '-1' : this.liTabindex}
            aria-label={this.item.label}>

            <label class={{
              'list-item flex items-center overlay-nc': true,
              'border-b border-fill border-opacity-moreTransparent text-secondary': this.item.isParent,
              'mx-disabled': this.item.disabled
            }}>
              {this.item.prefixElement && iconPrefixElement(this.item.prefixElement)}
              {this.item.label}
            </label>

            {this.item && !this.item.children && this.actions && this.actions.length > 0 && (
              <div class='mx-dropdown-item-actions flex items-center'>
                {actionsFiltered.map((action: IMxSingleSelectListItemAction) => {
                  const Icon: string = typeof action.icon === 'string' ? action.icon : action.icon(this.item);
                  return (<Icon
                    class={`
                    mx-dropdown-item-action
                    ${(actionsFiltered.length > 0 && this.activeIndex === this.item.index
                      ? action.activeClassName || 'text-primary-inverse'
                      : action.className || '')}
                   `}
                    onClick={this.handleActionInteractions(action)}
                  />);
                })
                }
              </div>
            )}
          </li>
          {this.item && this.item.children && (
            <Fragment>
              {this.item.children?.map((childItem) => (
                <mx-single-select-list-item
                  class='mx-single-select-list'
                  item={childItem}
                  selectedItem={this.selectedItem}
                  emit-only-value={this.emitOnlyValue}
                  actions={this.actions}
                  active-index={this.activeIndex}
                  liTabindex={this.liTabindex}
                />
              ))}
            </Fragment>
          )}
        </div>
      </Host>
    );
  }
}
