import { Component, Event, EventEmitter, h, Host, Listen, Prop, Element, State, Watch, Method } from '@stencil/core';
import {
  closeAllDropdownsInZG,
  findMatchedItem,
  isNullOrUndefined,
  isNullOrUndefinedOrEmptyString,
  iconPrefixElement
} from '@src/utils/mx-utils/utils';
import { EventTypes, KeyboardCodes } from '@src/utils/mx-utils/Events';
import isEqual from 'lodash.isequal';
import isEmpty from 'lodash.isempty';
import isString from 'lodash.isstring';
import { DomHandler } from '@src/utils/mx-utils/domhandler';
import { Item } from '@src/utils/mx-utils/calendar-service';
import { IMxSingleSelectListItemAction } from '../mx-single-select-list-item/mx-single-select-list-item.model';
import { autoUpdate, computePosition, flip, offset } from '@floating-ui/dom';
import { debounce } from '@src/utils/mx-utils';

@Component({
  tag: 'mx-single-select',
  styleUrl: 'mx-single-select.css'
})
export class MxSingleSelect {
  @Element() hostEl: HTMLMxSingleSelectElement;

  /** Sets the single select name. */
  @Prop({ reflect: true, attribute: 'name' }) readonly name: string;
  /** Displays filter search. */
  @Prop() readonly displayFilterSearch: boolean = false;
  /** Displays the optionalText next to the label. */
  @Prop() readonly displayOptionalText: boolean = false;
  /** Returns value only of select item if true. */
  @Prop({ mutable: true }) emitOnlyValue = false;
  /** Provide placeholder text to select list. */
  @Prop() readonly placeHolder: string = 'Select One';
  /** Sets placeholder content in the filter search to provide additional information. */
  @Prop() readonly filterSearchPlaceholder: string = '';
  /** Sets error class in single-select. */
  @Prop() readonly hasError: boolean = false;
  /** The visible label text for the single-select. */
  @Prop() readonly label?: string;
  /** When true, the size of the single-select input is smaller. Set to false by default. */
  @Prop() readonly isCompact: boolean = false;
  /** Disables the single-select menu, set to false by default. */
  @Prop() readonly isDisabled: boolean = false;
  /** The id used for the label attr.for and input attr.id. */
  @Prop() readonly inputId: string;
  /** Array of SelectItems (example: {label: 'Carrot', value: 'carrot'}) or primitive values. */
  @Prop({ mutable: true }) items: Item[] | string[] = [];
  /** Sets the item currently selected. */
  @Prop({ mutable: true }) itemSelected?: Item | string;
  /** DO NOT USE DIRECTLY. NOT MEANT FOR CONSUMER USE. Sets the item currently selected by ngModel. */
  @Prop({ mutable: true }) value?: Item | string;

  @Watch('value')
  onValueChange(newValue: any, oldValue: any) {
    if (!isEqual(newValue, oldValue)) {
      this.itemSelected = newValue;
      this.valueUpdate.emit(newValue);
    }
  }

  /** Sets the number of keystrokes on which filter search should trigger the search. */
  @Prop() readonly keyStrokes: number = 0;
  /** Allows for setting the optional text displayed. */
  @Prop() readonly optionalText: string = 'Optional';
  /** Sets the width of single-select. */
  @Prop() readonly width: string = '100%';
  /** Sets the width of single-select list. */
  @Prop() readonly listWidth: string = '100%';
  /** Renders a drop-up menu instead of drop-down menu if the select is less than 220px above viewport bottom. */
  @Prop() readonly enableDropUp: boolean = true;
  /** Enables a clear icon on select list to clear selection. */
  @Prop() readonly enableClearSelection: boolean = false;
  /** Target single-select options list to attach the dialog, valid values are 'body' or a local ng-template variable of another element. */
  @Prop() readonly appendTo: any;
  /** Specifies a collection of action buttons to be presented within the single-select list. */
  @Prop() readonly itemActions: Array<IMxSingleSelectListItemAction>;
  /** Overrides the single-select’s bottom position to one of your choosing in px. */
  @Prop() readonly dropdownBottomPosition: string;
  /** Enables or disables the virtual scroll functionality to increase performance.
   * Enabling this may cause style issues when font sizes or zoom levels are changed from their defaults.
   * Disabled by default. */
  @Prop() readonly enableVirtualScroll: boolean = false;

  @State() val: any;
  @State() isOpen = false;
  @State() searchText = '';
  @State() selectedItem: Item;
  @State() formattedSelectedItem: Item;
  @State() selectedLabel: string = '';
  @State() listContainerWidth: string = this.getWidth(this.listWidth, null);
  @State() highlightedIndex: number = -1;

  /** Emits event on single-select change with the selected object.     */
  @Event() itemChange: EventEmitter;
  /** Emits event on single-select value is cleared.     */
  @Event() itemClear: EventEmitter;
  /** Emits event on single-select search input blur.     */
  @Event() inputBlur: EventEmitter;
  /** Emits event on single-select close.     */
  @Event() dropdownClose: EventEmitter<HTMLDivElement>;
  /** Emits event on single-select open. */
  @Event() dropdownOpen: EventEmitter<HTMLDivElement>;
  // Had to add a separate event to handle ngModel support because using itemChange is breaking other components that use single-select.
  /** DO NOT USE DIRECTLY. NOT MEANT FOR CONSUMER USE. Emits an event whenever the 'value' property is updated. This is used for ngModel. */
  @Event() valueUpdate: EventEmitter;
  /** Event fired when single-select is opened after it has been rendered. */
  @Event() dropdownOpenRendered: EventEmitter<HTMLDivElement>;
  /** Event fired when single-select is opened after it has been closed. */
  @Event() dropdownCloseRendered: EventEmitter<HTMLDivElement>;

  private searchInputRef: HTMLMxSearchInputElement;
  private singleSelectListRef: HTMLMxSingleSelectListElement;

  private listContainerRef: HTMLDivElement;
  private inputWrapperRef: HTMLDivElement;
  private cleanupAutoUpdate: () => void;
  private shouldFireOpenRendered: boolean;
  private shouldFireCloseRendered: boolean;



  @Watch('isOpen')
  //watching this isOpen to set the shouldFireOpenRendered = true so that we can re-calculate
  //the height after listening to dropdownOpenRendered so that dropdown list is visible without scrolling in section-accordion
  checkIsOpen(newOpen: boolean, prevOpen: boolean) {
    if (newOpen === true && prevOpen === false) {
      this.shouldFireOpenRendered = true;
    } else if (newOpen === false && prevOpen === true) {
      this.shouldFireCloseRendered = true;
    }
  }


  private filteredData: Item[] | string[];

  constructor() {
    // This needs to happen in the constructor because arrow functions are not allowed in @Method().
    this.clearSelection = this.clearSelection.bind(this);
    if (isNullOrUndefined(this.value)) {
      this.value = this.itemSelected;
    } else {
      this.itemSelected = this.value;
    }
  }

  private moveHighlight(delta: number) {
    const list = this.filteredData || this.items || [];
    if (!list.length) return;
    let newIndex = this.highlightedIndex + delta;
    if (newIndex < 0) newIndex = list.length - 1;
    if (newIndex >= list.length) newIndex = 0;
    this.highlightedIndex = newIndex;
    this.scrollToHighlightedItem();
  }

  private selectHighlightedItem() {
    const list = this.filteredData || this.items || [];
    if (this.highlightedIndex >= 0 && list[this.highlightedIndex]) {
      const selected = list[this.highlightedIndex];
      (window as any).keyboardSelectTriggered = true;
      this.selectSingleItem(selected);
    }
  }

  private scrollToHighlightedItem() {
    requestAnimationFrame(() => {
      const listEl = this.singleSelectListRef?.shadowRoot?.querySelectorAll('.mx-single-select-list-item');
      if (!listEl || listEl.length === 0) return;

      const highlightedItemEl = listEl[this.highlightedIndex] as HTMLElement;
      highlightedItemEl?.scrollIntoView({ block: 'nearest', behavior: 'smooth' });
    });
  }

  @Listen('click', { target: 'document' })
  docClick(event) {
    if (!this.hostEl.contains(event.target) && this.isOpen) {
      this.closeDropdown();
    } else if (this.hostEl.contains(event.target) &&
      this.isOpen && event.target && (event.target.classList.contains('kds-Label') ||
        event.target.classList.contains('optional-text'))) {
      this.closeDropdown();
    }
  }
  componentDidLoad() {
    this.listContainerRef?.addEventListener('keydown', this.handleDropdownKeyboardEvents);
  }

  @Listen('keydown', { target: 'document' })
  handleDropdownKeyboardEvents(event: KeyboardEvent) {
    const active = document.activeElement;
    const isWithinHost = !!this.hostEl &&
      (this.hostEl === active || this.hostEl.contains(active) || this.hostEl.shadowRoot?.contains(active));
    if (!isWithinHost) return;
    switch (event.code) {
      case 'Escape':
        this.closeDropdown();
        break;

      case 'Space':
      case 'Enter':
        event.preventDefault();
        if (!this.isOpen) {
          this.toggleDropdown(true);
        } else {
          if (this.highlightedIndex >= 0) {
            this.selectHighlightedItem();
          }
        }
        break;

      case 'ArrowDown':
        event.preventDefault();
        this.moveHighlight(1);
        break;

      case 'ArrowUp':
        event.preventDefault();
        this.moveHighlight(-1);
        break;
    }
  }

  @Listen('focus', { target: 'document' })
  focusHandler(_event) {
    const inputComponent: HTMLElement = this.hostEl.querySelector('.mx-dropdown-input-wrapper');
    inputComponent.focus();
  }

  @Listen('resize', { target: 'window' })
  watchWindowResize() {
    this.listContainerWidth = this.getWidth(this.listWidth, this.inputWrapperRef);
  }

  @Watch('itemSelected')
  watchItemSelected(newValue: Item, oldValue: Item) {
    if (!isEqual(newValue, oldValue)) {
      this.updateSelectedItem(newValue);
    }
  }

  componentWillLoad() {
    if (!isNullOrUndefined(this.itemSelected)) {
      this.selectedItem = this.mapItemSelected(this.itemSelected);

      // Ternary ensures "value" is initialized correctly based off emitOnlyValue flag
      this.updateSelectedItem(this.emitOnlyValue ? this.selectedItem.value : this.selectedItem);
    }
  }

  private mapItemSelected(itemSelected: string | Item): Item {
    if (typeof itemSelected == 'string') {
      return { label: itemSelected, value: itemSelected } as Item;
    } else {
      return {
        label: itemSelected?.label,
        value: itemSelected?.value,
        prefixElement: itemSelected?.prefixElement,
        children: itemSelected?.children
      } as Item;
    }
  }

  private updateSelectedItem(itemSelected) {
    if (itemSelected == null) {
      this.val = '';
      this.selectedItem = { label: '', value: '', prefixElement: '' };
    } else {
      this.val = itemSelected;
      this.selectedItem = this.mapItemSelected(this.itemSelected);
    }

    this.formattedSelectedItem = this.selectedItem;
    let label = this.getDropdownLabel();
    if (isNullOrUndefinedOrEmptyString(label)) {
      label = itemSelected;
    }
    this.selectedLabel = label || '';
    this.value = this.val;
  }

  componentWillRender() {
    this.handleFilterChange(null);
    this.selectedLabel = this.getDropdownLabel();
  }

  componentDidRender() {
    if (isNullOrUndefined(this.items)) {
      this.items = [];
    }
    if (this.items.length > 0 && typeof this.items[0] === 'string') {
      this.items = this.items.map((itemVal) => ({ label: itemVal, value: itemVal }));
      this.emitOnlyValue = true;
    }
    this.listContainerWidth = this.getWidth(this.listWidth, this.inputWrapperRef);
  }

  componentDidUpdate() {
    this.shouldFireOpenRendered && this.dropdownOpenRendered.emit();
    this.shouldFireCloseRendered && this.dropdownCloseRendered.emit();
    this.shouldFireOpenRendered = false;
    this.shouldFireCloseRendered = false;
  }

  disconnectedCallback() {
    this.listContainerRef?.remove();

  }
  private readonly onItemSelectedFromList = (event: CustomEvent) => {
    this.selectSingleItem(event.detail);
  };

  private readonly selectSingleItem = (event) => {
    const item = event?.detail ? event.detail : event;
    this.val = this.emitOnlyValue ? item?.children && item.children.length > 0 ?
      item.children[0].value : item?.value : item;

    this.itemSelected = this.val;
    this.value = this.val;
    this.selectedLabel = this.getDropdownLabel();
    this.itemChange.emit(this.val);
    this.closeDropdown();
    this.getSelectedItem(this.val);
  };

  private getSelectedItem(value) {
    if (isNullOrUndefinedOrEmptyString(value)) {
      this.selectedItem = null;
      this.formattedSelectedItem = null;
      return;
    }
    if (this.val && typeof (value) === 'object') {
      this.selectedItem = value;
      this.formatSelectedItem();
      return;
    }
    this.selectedItem = { label: this.getLabelItem().label, value: this.val };
    this.formatSelectedItem();
  }

  private getDropdownLabel() {
    const SELECT_ONE = this.placeHolder;
    if (this.items.length === 0) {
      return SELECT_ONE;
    }

    if (isNullOrUndefined(this.val) || this.val === '') {
      return SELECT_ONE;
    }
    return this.getLabelItem().label;
  }

  private getPrefixElement() {
    if (this.items.length === 0 || isNullOrUndefined(this.val) || this.val === '') {
      return '';
    }
    return this.getLabelItem().prefixElement;
  }

  private getLabelItem() {
    let labelItem: Item = { label: '', prefixElement: '', value: '' };
    this.items.forEach((item) => {
      if (item && !item.children && this.itemFound(item)) {
        labelItem = item;
        return;
      }
      if (item.children) {
        item.children.forEach((childItem) => {
          if (this.itemFound(childItem)) {
            labelItem = childItem;
          }
        });
      }
    });
    return labelItem;
  }

  private itemFound(item) {
    const val = this.val && this.val.children && this.val.children.length > 0 ?
      (this.emitOnlyValue ? this.val.children[0].value : this.val.children[0]) : this.val;

    if (!isString(val) && this.emitOnlyValue) {
      return isEqual(item.value, val.value);
    }
    return isEqual(item.value, (this.emitOnlyValue ? val : val.value));
  }

  private readonly computeDropdownPosition = () => {
    this.cleanupAutoUpdate = autoUpdate(this.inputWrapperRef, this.listContainerRef, () => {
      computePosition(this.inputWrapperRef, this.listContainerRef, {
        placement: this.enableDropUp ? 'top-start' : 'bottom-start',
        strategy: 'absolute',
        middleware: [
          offset(0),
          flip()
        ]
      })
        .then(({ x, y, placement }) => {
          const [side, _] = placement.split('-');
          Object.assign(this.listContainerRef.style, { left: `${x}px`, top: `${y}px` });
          if (side !== 'bottom') {
            this.listContainerRef.style.transform = `translateY(1px)`;
          } else {
            if (this.displayFilterSearch) {
              this.listContainerRef.style.transform = this.isCompact ? `translateY(-32px)` : `translateY(-40px)`;
            } else {
              this.listContainerRef.style.transform = `translateY(0)`;
            }
          }
        });
    });
  };

  private readonly toggleOptionsMenu = (event) => {
    if (this.isDisabled) {
      return;
    }
    const eventCodeOrType = event.code !== undefined ? event.code : event.type;

    switch (eventCodeOrType) {
      case KeyboardCodes.SPACE:
      case KeyboardCodes.ENTER:
      case KeyboardCodes.NUMPAD_ENTER:
      case EventTypes.CLICK:
        this.actionToPerformOnToggle();
        break;
      case KeyboardCodes.ESCAPE:
        this.closeDropdown();
        break;
    }
  };

  private async actionToPerformOnToggle() {

    if (this.isOpen) {
      this.closeDropdown();
      return;
    }

    // If this is used inside ZingGrid, we need to close all other dropdowns before opening this one.
    await closeAllDropdownsInZG(this.hostEl);
    this.toggleDropdown(true);
    if (this.isOpen && this.appendTo) {
      if (this.appendTo === 'body') {
        document.body.appendChild(this.listContainerRef);
      } else {
        DomHandler.appendChild(this.listContainerRef, this.appendTo);
      }
    }

    if (this.isOpen) {
      this.listContainerRef.style.display = 'block';

      if (this.displayFilterSearch) {
        this.searchInputRef.setFocus().then(console.debug);
      }
    }
  }

  private readonly handleFilterChange = (ev) => {

    if (this.isOpen && this.listContainerRef && !isEmpty(this.singleSelectListRef)) {
      this.singleSelectListRef.setSpaceAndHeight().then(console.debug);
    }

    if (ev) {
      this.searchText = ev.detail.searchText;
    }

    if (!this.hasKeyStrokeLength()) {
      return;
    }

    if (isNullOrUndefined(this.items) || this.items.length === 0) {
      this.filteredData = [];
      return;
    }

    this.filteredData = [];
    this.items.forEach((item) => {
      const result = findMatchedItem(item, this.searchText);
      if (!isEmpty(result)) {
        this.filteredData.push(result);
      }
    });
  };

  private hasKeyStrokeLength(): boolean {
    return !(this.searchText.length && this.searchText.length < this.keyStrokes);
  }

  private formatSelectedItem() {
    if (!isNullOrUndefined(this.selectedItem) && !isNullOrUndefined(this.selectedItem.children)) {
      this.formattedSelectedItem = { ...this.selectedItem.children[0] };
      return;
    }
    this.formattedSelectedItem = this.selectedItem;
  }

  /** Toggles the opened status of the dropdown. Optionally, you may pass in a value to show it or hide it.*/
  @Method()
  async toggleDropdown(toggle?: boolean) {
    this.isOpen = !isNullOrUndefined(toggle) ? toggle : !this.isOpen;
    if (this.isOpen) {
      this.handleOpenDropdown();
    } else {
      this.closeDropdown();
    }
  }
  private getIndexOfSelectedItem(): number {
    const list = this.filteredData || this.items || [];
    const selectedValue = this.value && typeof this.value === 'object' ? this.value.value : this.value;
    return list.findIndex((item) => item?.value === selectedValue);
  }

  private handleOpenDropdown() {
    const selectedIndex = this.getIndexOfSelectedItem();
    // If no item selected, highlight first item (index 0)
    this.highlightedIndex = selectedIndex !== -1 ? selectedIndex : 0;
    this.listContainerRef.style.display = 'block';
    this.computeDropdownPosition();
    this.dropdownOpen.emit(this.listContainerRef);

    if (this.displayFilterSearch) {
      this.searchInputRef.setFocus().then(console.debug);
    }
  }

  /** Clear the selected item from single-select. */
  @Method()
  async clearSelection(event?: MouseEvent) {
    if (this.isDisabled) {
      return;
    }
    // required to clear the dropdown using the ref
    event?.stopPropagation();
    this.val = '';
    this.selectedItem = { label: '', value: '' };
    this.formattedSelectedItem = this.selectedItem;
    this.selectedLabel = this.getDropdownLabel();
    this.itemSelected = undefined;
    this.itemClear.emit();
  }

  private readonly closeDropdown = () => {
    this.isOpen = false;
    this.searchText = '';
    this.listContainerRef.style.display = 'none';
    this.cleanupAutoUpdate && this.cleanupAutoUpdate(); // clear-up auto-update
    this.dropdownClose.emit(this.listContainerRef);
  };

  private getWidth(width: string, ref?: HTMLElement | null): string {
    if (width !== '100%') {
      return width;
    } else {
      return ref?.offsetWidth ? `${ref?.offsetWidth}px` : width; // 200px fixed for exception
    }
  }

  render() {
    return (
      <Host>
        <div
          class={{
            'mx-single-select': true,
            'mx-dropdown-wrapper': true,
            'has-error': this.hasError
          }}
          style={{ width: this.width || '100%' }}
        >
          {this.label && (
            <kds-label class={{
              'mb-4 mx-label': true,
              'text-primary': !this.hasError,
              'text-negative-less-prominent': this.hasError
            }}>
              {this.label}
              {this.displayOptionalText && (
                <span class={{
                  'optional-text': true,
                  'text-secondary': !this.hasError,
                  'text-negative-less-prominent': this.hasError
                }}>
                  ({this.optionalText})
                </span>
              )}
            </kds-label>
          )}
          <div
            ref={(ref: HTMLDivElement) => this.inputWrapperRef = ref}
            role='combobox'
            aria-haspopup='listbox'
            aria-expanded={this.isOpen ? "true" : "false"}
            class={{
              'mx-dropdown-input-wrapper border border-neutral-less-prominent': true,
              'focus:border-informative-less-prominent hover:border-neutral-most-prominent': !this.isDisabled,
              'disabled text-secondary bg-quaternary-fill': this.isDisabled,
              'border-negative-less-prominent': this.hasError,
              compact: this.isCompact,
              open: this.isOpen
            }}
            title={this.selectedLabel.length > 0 ? this.selectedLabel : this.placeHolder}
            onClick={this.toggleOptionsMenu}
            aria-label={this.label && this.label.length > 0 ? this.label : 'ariaLabel'}
            tabIndex={this.isDisabled ? -1 : 0}>

            <span
              class={{
                flex: true,
                'items-center': true,
                'mx-dropdown-label': true,
                disabled: this.isDisabled,
                open: this.isOpen
              }}
              style={{ paddingLeft: '0' }}>
              {this.getPrefixElement() && iconPrefixElement(this.getPrefixElement())}
              {this.selectedLabel.length > 0 ? this.selectedLabel : this.placeHolder}
            </span>

            {this.enableClearSelection &&
              <kds-icon-close
                size='s'
                class={{
                  'mx-dropdown-icon': true,
                  'disabled text-secondary': this.isDisabled
                }}
                tabindex='0'
                onClick={this.clearSelection} />
            }
            <kds-icon-chevron-down
              class={{
                'mx-dropdown-icon': true,
                'disabled text-secondary': this.isDisabled,
                open: this.isOpen
              }}
              size='m' />
          </div>
          <div
            ref={(el) => this.listContainerRef = el}
            style={{ width: this.listContainerWidth }}
            class={{
              'mx-single-select-container': true,
              'mx-dropdown-list': true,
              'is-compact': this.isCompact,
              'has-search': this.displayFilterSearch
            }}
          >

            {this.displayFilterSearch &&
              <mx-search-input
                ref={(el) => this.searchInputRef = el}
                class='filter-search'
                key-strokes={this.keyStrokes}
                placeholder={this.filterSearchPlaceholder}
                onFocusout={this.inputBlur.emit}
                onInputChanged={debounce(this.handleFilterChange, 700)}
                value={this.searchText}
                is-compact={this.isCompact} />
            }

            <mx-single-select-list
              ref={(ref: HTMLMxSingleSelectListElement) => this.singleSelectListRef = ref}
              class='mx-single-select-list'
              items={this.filteredData}
              selectedItem={this.formattedSelectedItem}
              emit-only-value={this.emitOnlyValue}
              highlighted-index={this.highlightedIndex}
              itemActions={this.itemActions}
              enableVirtualScroll={this.enableVirtualScroll}
              highlightedIndex={this.highlightedIndex}
              onItemSelectedFromList={this.onItemSelectedFromList} />
          </div>
        </div>
      </Host>
    );
  }
}
