import { Component, Element, Event, EventEmitter, h, Method, Prop, State } from '@stencil/core';
import { KeyboardTypes } from '@src/utils/mx-utils/Events';
import { isNullOrUndefined, isNullOrUndefinedOrEmptyString } from '@src/utils/mx-utils/utils';
import isEqual from 'lodash.isequal';
import { IMxSingleSelectListItemAction } from '../mx-single-select-list-item/mx-single-select-list-item.model';
import { iSelectedItem, SelectListItem } from '@src/utils/mx-utils/calendar-service';
import menuItemUtils from '@src/utils/mx-utils/mx-menu-item.utils';
import 'stencil-virtual-scroll';

@Component({
  tag: 'mx-single-select-list',
  styleUrl: 'mx-single-select-list.css'
})
export class MxSingleSelectList {
  @Element() hostEl: HTMLMxSingleSelectListElement;
  /** Array of SelectItems (example: {label: 'Carrot', value: 'carrot'}) or primitive values. */
  @Prop() readonly items: Array<any>;
  /** The item currently selected (example: {label: 'Apple', value: 'apple'}). */
  @Prop({ mutable: true }) selectedItem: iSelectedItem;
  /** Returns value ONLY of select item if true. */
  @Prop() readonly emitOnlyValue: boolean = false;
  /** Array of item actions. */
  @Prop() readonly itemActions: Array<IMxSingleSelectListItemAction>;
  /** Enables or disables the virtual scroll functionality to increase performance.
   * Enabling this may cause style issues when font sizes or zoom levels are changed from their defaults.
   * Disabled by default. */
  @Prop() readonly enableVirtualScroll: boolean = false;
  /** The index of the item to highlight. */
  @Prop({ mutable: true }) highlightedIndex: number;
  /** Emits the item selected. */
  @Event() itemSelectedFromList: EventEmitter;

  @State() formattedItems: SelectListItem[] = [];
  @State() listHeight = '0px';

  @State() activeIndex: number

  constructor() {
    this.items = [];
  }

  /**
   * Used on the parent to re-calculate the height when search is used
   */
  @Method()
  async setSpaceAndHeight() {
    this.updateViewPortHeight();
  }

  async componentWillLoad() {
    this.formatItems();
    await this.setSpaceAndHeight();
    this.items.forEach((item) => {
      if (!isNullOrUndefined(item.children) && item.children.every((data) => data.disabled)) {
        item.disabled = true;
      }
    });
  }

  componentWillRender() {
    this.formatItems();
    if (!isNullOrUndefined(this.selectedItem)) {
      this.activeIndex = this.findIndexByValue(this.formattedItems, this.selectedItem.value);
    }
  }

  private formatItems() {
    let index = 0;
    this.formattedItems = this.items.map((origItem) => {
      const item = { ...origItem };
      item.isParent = false;
      item.isChild = false;
      item.isLeafNode = false;
      item.index = index;
      index += 1;
      if (item.children) {
        item.isParent = true;
        item.children = item.children.map((origChildItem) => {
          const childItem = { ...origChildItem };
          childItem.isChild = true;
          childItem.isParent = false;
          childItem.isLeafNode = false;
          childItem.parent = { label: item.label, value: item.value, index: item.index };
          childItem.index = index;
          index += 1;
          return childItem;
        });
      } else {
        item.isLeafNode = true;
      }
      return item;
    });
  }

  private readonly onKeyDown = (event: KeyboardEvent) => {
    const actions = {
      [KeyboardTypes.ARROW_UP]: () => this.getActiveIndex(false),
      [KeyboardTypes.ARROW_DOWN]: () => this.getActiveIndex(true),
      [KeyboardTypes.ENTER]: () => this.selectItem(event, this.findItemByIndex(this.formattedItems, this.activeIndex)),
      [KeyboardTypes.SPACE]: () => this.selectItem(event, this.findItemByIndex(this.formattedItems, this.activeIndex))
    };


    if (Object.keys(actions).includes(event.key)) {
      actions[event.key]();
      event.preventDefault();
      this.setFocus();
    } else {
      this.searchForListItem(event.key);
    }
  };

  private selectItem(event, item) {
    this.selectItemHandler(item);
    event.stopPropagation();
  }

  private readonly selectItemHandler = (event) => {
    let item;

    if (event.detail) {
      item = event.detail;
    } else {
      item = event;
    }

    const obj = { ...item };
    delete obj.isParent;
    const isChild = obj.isChild;
    delete obj.isChild;
    delete obj.isLeafNode;
    delete obj.index;
    if (obj.parent) {
      delete obj.parent.index;
    }
    let returnObj = { ...obj };
    if (isChild) {
      const child = {
        ...obj
      };
      const parent = {
        ...child.parent
      };
      delete child.parent;
      returnObj = {
        ...parent,
        children: [{ ...child }]
      };
    }

    this.selectedItem = obj;
    this.itemSelectedFromList.emit(returnObj);

  };

  private getActiveIndex(isNext) {
    if (isNext) {
      this.getNextActiveIndex();
      return;
    }
    this.getPreviousActiveIndex();
  }

  private getPreviousActiveIndex() {
    if (this.activeIndex === 0) {
      return;
    }
    this.activeIndex -= 1;
    while (this.isParentItem(this.activeIndex)) {
      this.activeIndex -= 1;
    }
  }

  private getNextActiveIndex() {
    if (this.activeIndex === menuItemUtils.getItemsLength(this.formattedItems) - 1) {
      return;
    }
    this.activeIndex += 1;
    while (this.isParentItem(this.activeIndex)) {
      this.activeIndex += 1;
    }
  }

  private setFocus() {
    setTimeout(() => {
      if (!isNullOrUndefined(this.hostEl.querySelector('.mx-active'))) {
        const activeElement: HTMLElement = this.hostEl.querySelector('.mx-active');
        activeElement.focus();
      }
    }, 0);
  }

  private searchForListItem(key) {
    const alpha = /^[a-zA-Z]+$/;
    if (key && key.match(alpha) && key.length === 1) {
      const firstLetter = key.toLowerCase();
      const filteredIndex = this.findIndexByContainingKey(this.formattedItems, firstLetter);
      if (filteredIndex > -1) {
        this.activeIndex = filteredIndex;
        this.setFocus();
      }
    }
  }

  private readonly onFocus = () => {
    if (
      isNullOrUndefined(this.selectedItem) ||
      !(this.selectedItem.hasOwnProperty('label') && !isNullOrUndefinedOrEmptyString(this.selectedItem.label)) ||
      !this.hasSelectedItemInList()
    ) {
      this.activeIndex = isNullOrUndefined(this.selectedItem) ? -1 : 0;
      while (this.isParentItem(this.activeIndex)) {
        this.activeIndex += 1;
      }
    } else {
      this.activeIndex = this.findIndexByValue(this.formattedItems, this.selectedItem.value);
    }
  };

  private isSelected(item) {
    return this.selectedItem && this.selectedItem.value === item.value;
  }

  private hasSelectedItemInList() {
    return this.items.findIndex((item) => this.isSelected(item)) > -1;
  }

  private updateViewPortHeight(): void {
    if (!isNullOrUndefined(this.formattedItems)) {
      const height: number = menuItemUtils.calculateListHeight(this.formattedItems, 34);
      this.listHeight = height + 'px';
      return;
    }
    this.listHeight = 0 + 'px';
  }

  private isParentItem(index) {
    return this.formattedItems.filter((item) => item.index === index && item.isParent).length > 0;
  }

  private hasChildren(items) {
    return items.filter((item) => !isNullOrUndefined(item.children) && item.children.length > 0);
  }

  private findItemByIndex(items = this.formattedItems, index) {
    const itemFound = items.filter((item) => item.index === index);
    if (itemFound.length !== 0) {
      return itemFound[0];
    }
    const hasChildren = this.hasChildren(items);
    if (hasChildren.length === 0) {
      return {};
    }
    let childItems = [];
    hasChildren.forEach((item) => (childItems = [...childItems, ...item.children]));
    return this.findItemByIndex(childItems, index);
  }

  private findIndexByValue(items = this.formattedItems, value) {
    const itemFound = items.filter((item) => isEqual(item.value, value));
    if (itemFound.length !== 0) {
      return itemFound[0].index;
    }
    const hasChildren = this.hasChildren(items);
    if (hasChildren.length === 0) {
      return -1;
    }
    let childItems = [];
    hasChildren.forEach((item) => (childItems = [...childItems, ...item.children]));
    return this.findIndexByValue(childItems, value);
  }

  private findIndexByContainingKey(items = this.formattedItems, containingKey) {
    const itemFound = items.filter((item) => item.label[0].toLowerCase() === containingKey);
    if (itemFound.length !== 0) {
      return itemFound[0].index;
    }
    const hasChildren = this.hasChildren(items);
    if (hasChildren.length === 0) {
      return -1;
    }
    let childItems = [];
    hasChildren.forEach((item) => (childItems = [...childItems, ...item.children]));
    return this.findIndexByContainingKey(childItems, containingKey);
  }

  private getTabIndex(index) {
    return index === this.activeIndex ? 0 : -1;
  }

  render() {
    return (
      <ul
        class='mx-select-list border border-neutral-less-prominent bg-primary rounded-small'
        style={{ marginTop: '-0.05rem' }}
        role='list'
        tabindex='0'
        onFocusin={this.onFocus}
        onKeyDown={this.onKeyDown}>
        {isNullOrUndefined(this.formattedItems) || (this.formattedItems && this.formattedItems.length === 0) && (
          <li class='mx-list-item text-primary bg-primary items no-result'>
            <kds-label>No Results Found</kds-label>
          </li>
        )}
        <div class='view-port' style={{ height: this.listHeight }}>
          {!this.enableVirtualScroll ?
            this.formattedItems?.map((item, index) => (
              <mx-single-select-list-item
                role='option'
                aria-selected={item.value === this.selectedItem?.value ? "true" : "false"}
                item={item}
                index={index}
                active-index={this.highlightedIndex}
                selectedItem={this.selectedItem}
                liTabindex={this.getTabIndex(index)}
                actions={this.itemActions}
                onItemSelected={this.selectItemHandler}
                isHighlighted={index === this.highlightedIndex}
                setHighlightedIndex={(i) => this.highlightedIndex = i}
              />
            )) : this.renderSingleSelectList()
          }
        </div>
      </ul>
    );
  }

  private renderItem(index: number) {
    return <mx-single-select-list-item
      item={this.formattedItems[index]}
      active-index={this.activeIndex}
      selectedItem={this.selectedItem}
      liTabindex={this.activeIndex != null ? 0 : -1}
      actions={this.itemActions}
      style={{ width: '100%' }}
      onItemSelected={this.selectItemHandler}
    />;
  }

  // Needed to dynamically render the list of items based off what is currently visible.
  private renderSingleSelectList() {
    let estimatedItemHeight = 34;
    let itemHeights = [];
    this.formattedItems.forEach((item) => {
      let height = 34;
      if (item.children) {
        height *= item.children.length;
        // parent label
        height += 34;
      }
      itemHeights.push(height);
    });

    const itemWidth = this.hostEl.parentElement.clientWidth;

    return (<virtual-scroll-list
      itemCount={this.formattedItems.length}
      renderItem={(i) => this.renderItem(i)}
      itemWidth={itemWidth}
      itemHeights={itemHeights}
      estimatedItemHeight={estimatedItemHeight}
      style={{
        display: 'flex',
        position: 'absolute',
        width: '100%',
        height: this.listHeight,
        'overflow-x': 'hidden',
        'overflow-y': 'auto'
      }}
    />);
  }
}
