import { Component, Host, h, Prop, Event, EventEmitter, Element, Method } from '@stencil/core';

@Component({
  tag: 'mx-search-input',
  styleUrl: 'mx-search-input.css',
  scoped: true
})
export class MxSearchInput {
  @Element() hostEl: HTMLMxSearchInputElement;

  /** Sets id of input text box. */
  @Prop() readonly inputId: string;
  /** Sets the search input with a search button at the end. */
  @Prop() readonly showSearchButton: boolean = false;
  /** Sets width of input text box. */
  @Prop() readonly width: string = 'auto';
  /** Sets the number of key strokes on which inputChanged event should be fired.
      Note: key-strokes only applies when searchOnEnter = false */
  @Prop() readonly keyStrokes: number = 0;
  /** Sets placeholder content to provide additional information in the text content. */
  @Prop() readonly placeholder: string = '';
  /** Sets disabled state of filter search component. */
  @Prop() readonly isDisabled: boolean = false;
  /** Sets the size to compact. */
  @Prop() readonly isCompact: boolean = false;
  /** Sets component to trigger search on enter. */
  @Prop() readonly searchOnEnter: boolean = false;
  /** The input's current value. */
  @Prop({ mutable: true }) value?: string = '';
  /** Sets the error state of the search input. */
  @Prop() readonly isInvalid: boolean = false;

  /** Emits event with object similar to { searchText: 'abc'}. */
  @Event() inputChanged: EventEmitter<{ searchText: string }>;

  /** A callback for when a search is performed; i.e. when Enter is pressed or the search button is clicked. */
  @Event() search: EventEmitter<{ searchText: string }>;

  private mxInputRef: HTMLKdsInputElement | null = null;

  private readonly _onChange = (event: KeyboardEvent) => {
    const input = event.target as HTMLInputElement;
    this.value = input.value;
    const isEnterKey = event.key === 'Enter';
    const isMinLengthReached = this.value.length >= parseInt(this.keyStrokes.toString(), 10);

    if (this.searchOnEnter === isEnterKey) {
      if (isMinLengthReached || isEnterKey) {
        this.inputChanged.emit({ searchText: this.value });
        if(isEnterKey) {
          this.search.emit({ searchText: this.value });
        }
      }

      if (this.value.length === 0) {
        this.inputChanged.emit({ searchText: '' });
      }
    }
  };

  private readonly _onSearch = () => {
    this.search.emit({ searchText: this.value });
  };

  /** Method to set focus on the input element. */
  @Method()
  async setFocus() {
    this.mxInputRef.querySelector('input')?.focus();
  }

  private readonly _clearInput = async (event: Event) => {
    event.preventDefault();
    event.stopPropagation();
    this.value = '';
    await this.setFocus();
    this.inputChanged.emit({ searchText: '' });
  };

  private readonly _kdsInputClasses = () => {
    const searchBorder = this.showSearchButton ? 'border-r-none kds-search-input' : '';
    // pr-32 to prevent text from overflowing onto the x icon
    return `hover:border-neutral-most-prominent focus:border-informative-less-prominent pr-32 ${searchBorder}`.trim();
  };

  render() {
    return (
      <Host style={{
        width: this.width
      }}>
        <div class='flex flex-row items-start mx-input-text-container'>
          <div class='mx-input-wrapper'>
            <kds-input ref={(ref) => this.mxInputRef = ref}
              type='text'
              id={this.inputId}
              placeholder={this.placeholder}
              aria-invalid={this.isInvalid}
              value={this.value}
              disabled={this.isDisabled}
              onKeyUp={this._onChange}
              compact={this.isCompact}
              inputClass={this._kdsInputClasses()}
              invalid={this.isInvalid}
            />
            <span class={{
              'mx-icon': true,
              compact: this.isCompact,
              disabled: this.isDisabled
            }}>

              {!this.value && !this.showSearchButton && (
                <kds-icon-search size='m'
                  class={{
                    'text-tertiary': !this.isInvalid && this.isDisabled,
                    [this.isInvalid ? 'text-negative-less-prominent' : 'text-primary']: true
                  }} />
              )}

              {this.value && !this.isDisabled && (
                <button class={{
                  'mx-close-icon-btn': true,
                  'text-quaternary': this.isDisabled
                }}
                disabled={this.isDisabled}
                onClick={this._clearInput}>
                  <kds-icon-close size='m' />
                </button>
              )}
            </span>


          </div>

          {this.showSearchButton && (
            <div class={{
              'mx-search-wrapper': true,
              disabled: this.isDisabled
            }}>
              <kds-button button-class={`mx-search-input__button ${this.isCompact ? 'h-32 w-32' : 'h-40 w-40'}`}
                disabled={this.isDisabled}
                onClick={this._onSearch}>
                <kds-icon-search size='m'
                  class={{
                    'text-primary-inverse': true
                  }} />
              </kds-button>
            </div>
          )}
        </div>
      </Host>
    );
  }
}
